import os
import pickle
import joblib
import json
import boto3
import google.cloud.storage as gcs
from azure.storage.blob import BlobServiceClient
import tensorflow as tf
import torch
import requests
from pathlib import Path
import tempfile
import shutil

class ModelLoader:
    def __init__(self):
        self.model_path = os.getenv('MODEL_PATH', 's3://models/default')
        self.local_cache = tempfile.mkdtemp()
        self.model = None
        self.cloud_provider = self._detect_cloud_provider()
        
    def _detect_cloud_provider(self):
        if self.model_path.startswith('s3://'):
            return 's3'
        elif self.model_path.startswith('gs://'):
            return 'gcs'
        elif self.model_path.startswith('https://') and 'blob.core.windows.net' in self.model_path:
            return 'azure'
        elif self.model_path.startswith('http://') or self.model_path.startswith('https://'):
            return 'http'
        else:
            return 'local'
    
    def _get_latest_version_s3(self, bucket, prefix):
        s3 = boto3.client('s3')
        response = s3.list_objects_v2(Bucket=bucket, Prefix=prefix)
        
        if 'Contents' not in response:
            return None
        
        objects = sorted(response['Contents'], key=lambda x: x['LastModified'], reverse=True)
        return objects[0]['Key'] if objects else None
    
    def _get_latest_version_gcs(self, bucket_name, prefix):
        client = gcs.Client()
        bucket = client.bucket(bucket_name)
        blobs = list(bucket.list_blobs(prefix=prefix))
        
        if not blobs:
            return None
        
        latest_blob = sorted(blobs, key=lambda x: x.updated, reverse=True)[0]
        return latest_blob.name
    
    def _get_latest_version_azure(self, container, prefix):
        connection_string = os.getenv('AZURE_STORAGE_CONNECTION_STRING')
        blob_service_client = BlobServiceClient.from_connection_string(connection_string)
        container_client = blob_service_client.get_container_client(container)
        
        blobs = list(container_client.list_blobs(name_starts_with=prefix))
        if not blobs:
            return None
        
        latest_blob = sorted(blobs, key=lambda x: x.last_modified, reverse=True)[0]
        return latest_blob.name
    
    def _download_from_s3(self, bucket, key, local_path):
        s3 = boto3.client('s3')
        s3.download_file(bucket, key, local_path)
    
    def _download_from_gcs(self, bucket_name, blob_name, local_path):
        client = gcs.Client()
        bucket = client.bucket(bucket_name)
        blob = bucket.blob(blob_name)
        blob.download_to_filename(local_path)
    
    def _download_from_azure(self, container, blob_name, local_path):
        connection_string = os.getenv('AZURE_STORAGE_CONNECTION_STRING')
        blob_service_client = BlobServiceClient.from_connection_string(connection_string)
        blob_client = blob_service_client.get_blob_client(container=container, blob=blob_name)
        
        with open(local_path, 'wb') as f:
            data = blob_client.download_blob()
            f.write(data.readall())
    
    def _download_from_http(self, url, local_path):
        response = requests.get(url, stream=True)
        with open(local_path, 'wb') as f:
            for chunk in response.iter_content(chunk_size=8192):
                f.write(chunk)
    
    def fetch_latest_model(self):
        if self.cloud_provider == 's3':
            path_parts = self.model_path.replace('s3://', '').split('/', 1)
            bucket = path_parts[0]
            prefix = path_parts[1] if len(path_parts) > 1 else ''
            
            latest_key = self._get_latest_version_s3(bucket, prefix)
            if latest_key:
                local_path = os.path.join(self.local_cache, os.path.basename(latest_key))
                self._download_from_s3(bucket, latest_key, local_path)
                return local_path
        
        elif self.cloud_provider == 'gcs':
            path_parts = self.model_path.replace('gs://', '').split('/', 1)
            bucket_name = path_parts[0]
            prefix = path_parts[1] if len(path_parts) > 1 else ''
            
            latest_blob = self._get_latest_version_gcs(bucket_name, prefix)
            if latest_blob:
                local_path = os.path.join(self.local_cache, os.path.basename(latest_blob))
                self._download_from_gcs(bucket_name, latest_blob, local_path)
                return local_path
        
        elif self.cloud_provider == 'azure':
            url_parts = self.model_path.split('/')
            container = url_parts[3]
            prefix = '/'.join(url_parts[4:]) if len(url_parts) > 4 else ''
            
            latest_blob = self._get_latest_version_azure(container, prefix)
            if latest_blob:
                local_path = os.path.join(self.local_cache, os.path.basename(latest_blob))
                self._download_from_azure(container, latest_blob, local_path)
                return local_path
        
        elif self.cloud_provider == 'http':
            local_path = os.path.join(self.local_cache, 'model')
            self._download_from_http(self.model_path, local_path)
            return local_path
        
        elif self.cloud_provider == 'local':
            return self.model_path
        
        return None
    
    def load_model(self, model_path):
        ext = os.path.splitext(model_path)[1].lower()
        
        if ext == '.pkl' or ext == '.pickle':
            with open(model_path, 'rb') as f:
                self.model = pickle.load(f)
        
        elif ext == '.joblib':
            self.model = joblib.load(model_path)
        
        elif ext == '.h5' or ext == '.keras':
            self.model = tf.keras.models.load_model(model_path)
        
        elif ext == '.pb':
            self.model = tf.saved_model.load(model_path)
        
        elif ext == '.pt' or ext == '.pth':
            self.model = torch.load(model_path)
        
        elif os.path.isdir(model_path):
            if os.path.exists(os.path.join(model_path, 'saved_model.pb')):
                self.model = tf.saved_model.load(model_path)
            elif os.path.exists(os.path.join(model_path, 'model.pt')):
                self.model = torch.load(os.path.join(model_path, 'model.pt'))
            else:
                with open(os.path.join(model_path, 'model.pkl'), 'rb') as f:
                    self.model = pickle.load(f)
        
        else:
            with open(model_path, 'rb') as f:
                self.model = pickle.load(f)
        
        return self.model
    
    def initialize(self):
        print(f"Fetching latest model from {self.model_path}")
        model_path = self.fetch_latest_model()
        
        if model_path:
            print(f"Loading model from {model_path}")
            self.load_model(model_path)
            print("Model loaded successfully")
        else:
            print("No model found")
        
        return self.model
    
    def predict(self, input_data):
        if self.model is None:
            raise ValueError("Model not loaded")
        
        if hasattr(self.model, 'predict'):
            return self.model.predict(input_data)
        elif callable(self.model):
            return self.model(input_data)
        else:
            raise ValueError("Model does not support prediction")
    
    def cleanup(self):
        if os.path.exists(self.local_cache):
            shutil.rmtree(self.local_cache)


